using Microsoft.EntityFrameworkCore;using verii_metivon_api.Core.Auth;using verii_metivon_api.Core.Paging;using verii_metivon_api.Core.Persistence;using verii_metivon_api.Core.UnitOfWork;using verii_metivon_api.Modules.Inventory.Application.Services;using verii_metivon_api.Modules.Inventory.Domain.Entities;using verii_metivon_api.Modules.Inventory.Domain.Enums;using verii_metivon_api.Modules.Products.Domain.Enums;using verii_metivon_api.Modules.Sales.Domain.Entities;using verii_metivon_api.Modules.Shipping.Application.Parameters;using verii_metivon_api.Modules.Shipping.Domain.Entities;using verii_metivon_api.Modules.Traceability.Application.Parameters;
using verii_metivon_api.Modules.NumberSeries.Application;
using verii_metivon_api.Modules.TradeOperations.Domain.Entities;
namespace verii_metivon_api.Modules.Shipping.Application.Services;
public sealed class ShipmentQuery:PagedQuery{public long?SalesOrderId{get;init;}public long?WarehouseId{get;init;}public ShipmentStatus?Status{get;init;}}
public sealed record ShipmentRow(long Id,string ShipmentNumber,string OrderNumber,string CustomerName,string WarehouseCode,DateOnly ShipmentDate,string Status,string?DeliveryNoteNumber,string?DeliveryNoteStatus);
public sealed record CreateShipmentLine(long SalesOrderLineId,decimal Quantity,IReadOnlyList<long>?InventorySerialIds);
public sealed record CreateShipmentRequest(string?ShipmentNumber,long?NumberSeriesId,long SalesOrderId,long?TradeDossierId,DateOnly ShipmentDate,string?CarrierName,string?VehiclePlate,string?DriverName,string?TrackingNumber,IReadOnlyList<CreateShipmentLine>Lines);
public interface IShipmentService{Task<ApiResponse<PagedResult<ShipmentRow>>>GetPagedAsync(ShipmentQuery q,CancellationToken ct);Task<ApiResponse<object>>CreateAsync(CreateShipmentRequest r,CancellationToken ct);Task<ApiResponse<object>>ShipAsync(long id,CancellationToken ct);}
public sealed class ShipmentService(IUnitOfWork u,IInventoryService inventory,IShippingParameterService parameters,IInventoryTraceabilityParameterService traceability,MetivonDbContext db,INumberSeriesService numberSeries):IShipmentService
{
 public async Task<ApiResponse<PagedResult<ShipmentRow>>>GetPagedAsync(ShipmentQuery q,CancellationToken ct){var x=u.Repository<Shipment>().Query().Include(v=>v.SalesOrder).ThenInclude(v=>v.Customer).Include(v=>v.Warehouse).Include(v=>v.DeliveryNote).AsQueryable();if(q.SalesOrderId.HasValue)x=x.Where(v=>v.SalesOrderId==q.SalesOrderId);if(q.WarehouseId.HasValue)x=x.Where(v=>v.WarehouseId==q.WarehouseId);if(q.Status.HasValue)x=x.Where(v=>v.Status==q.Status);if(!string.IsNullOrWhiteSpace(q.Search)){var s=q.Search.Trim();x=x.Where(v=>v.ShipmentNumber.Contains(s)||v.SalesOrder.OrderNumber.Contains(s));}x=x.ApplyPagedFilters(q);var total=await x.CountAsync(ct);var rows=await x.OrderByDescending(v=>v.ShipmentDate).Skip((q.NormalizedPageNumber-1)*q.NormalizedPageSize).Take(q.NormalizedPageSize).Select(v=>new ShipmentRow(v.Id,v.ShipmentNumber,v.SalesOrder.OrderNumber,v.SalesOrder.Customer.Name,v.Warehouse.Code,v.ShipmentDate,v.Status.ToString(),v.DeliveryNote!=null?v.DeliveryNote.DeliveryNoteNumber:null,v.DeliveryNote!=null?v.DeliveryNote.Status.ToString():null)).ToListAsync(ct);return ApiResponse<PagedResult<ShipmentRow>>.Ok(new(rows,q.NormalizedPageNumber,q.NormalizedPageSize,total));}
 public async Task<ApiResponse<object>>CreateAsync(CreateShipmentRequest r,CancellationToken ct)
 {
  if(r.Lines.Count==0)return ApiResponse<object>.Error("At least one shipment line is required.",400);
  var order=await u.Repository<SalesOrder>().Query().Include(x=>x.Lines).FirstOrDefaultAsync(x=>x.Id==r.SalesOrderId,ct);if(order is null)return ApiResponse<object>.Error("Sales order not found.",404);TradeDossier? trade=null;if(r.TradeDossierId.HasValue){trade=await db.TradeDossiers.FirstOrDefaultAsync(x=>x.Id==r.TradeDossierId,ct);if(trade is null||trade.Direction!=TradeDirection.Export)return ApiResponse<object>.Error("A valid export dossier is required.",400);if(trade.Status is TradeDossierStatus.Closed or TradeDossierStatus.Cancelled)return ApiResponse<object>.Error("Closed or cancelled trade dossier cannot be used.",409);}var p=await parameters.ResolveSettingsAsync(order.BranchId,order.WarehouseId,ct);var trace=await traceability.ResolveSettingsAsync(order.BranchId,order.WarehouseId,ct);
  var allowed=p.RequireFullReservation?order.Status is SalesOrderStatus.Reserved or SalesOrderStatus.PartiallyShipped:order.Status is SalesOrderStatus.PartiallyReserved or SalesOrderStatus.Reserved or SalesOrderStatus.PartiallyShipped;if(!allowed)return ApiResponse<object>.Error("Order reservation status is not ready for shipment.",409);
  if(!p.AllowPastShipmentDate&&r.ShipmentDate<DateOnly.FromDateTime(DateTime.UtcNow))return ApiResponse<object>.Error("Past shipment dates are disabled.",400);if(r.Lines.Count>p.MaximumLinesPerShipment)return ApiResponse<object>.Error($"A shipment can contain at most {p.MaximumLinesPerShipment} lines.",400);
  if(p.RequireCarrierName&&string.IsNullOrWhiteSpace(r.CarrierName))return ApiResponse<object>.Error("Carrier name is required.",400);if(p.RequireVehiclePlate&&string.IsNullOrWhiteSpace(r.VehiclePlate))return ApiResponse<object>.Error("Vehicle plate is required.",400);if(p.RequireDriverName&&string.IsNullOrWhiteSpace(r.DriverName))return ApiResponse<object>.Error("Driver name is required.",400);if(p.RequireTrackingNumber&&string.IsNullOrWhiteSpace(r.TrackingNumber))return ApiResponse<object>.Error("Tracking number is required.",400);
  if(!p.AllowPartialShipment){var requested=r.Lines.ToDictionary(x=>x.SalesOrderLineId,x=>x.Quantity);if(order.Lines.Where(x=>x.OrderedQuantity>x.ShippedQuantity).Any(x=>!requested.TryGetValue(x.Id,out var q)||q!=x.OrderedQuantity-x.ShippedQuantity))return ApiResponse<object>.Error("Partial shipment is disabled; all remaining order quantities must be shipped.",400);}
  ReservedNumber? reserved=null;var shipmentNumber=r.ShipmentNumber?.Trim();if(string.IsNullOrWhiteSpace(shipmentNumber)){reserved=await numberSeries.ReserveAsync(new("Shipping","ShipmentNumber",r.NumberSeriesId,order.BranchId,order.WarehouseId,null,order.CustomerId,null,null,r.ShipmentDate,"Shipment"),ct);shipmentNumber=reserved.DocumentNumber;}else shipmentNumber=await parameters.ResolveShipmentNumberAsync(shipmentNumber,order.BranchId,ct);var e=new Shipment{ShipmentNumber=shipmentNumber,Status=p.AutoMarkPackedOnCreate?ShipmentStatus.Packed:ShipmentStatus.Draft,SalesOrderId=order.Id,TradeDossierId=r.TradeDossierId,WarehouseId=order.WarehouseId,ShipmentDate=r.ShipmentDate,CarrierName=r.CarrierName?.Trim(),VehiclePlate=r.VehiclePlate?.Trim().ToUpperInvariant(),DriverName=r.DriverName?.Trim(),TrackingNumber=r.TrackingNumber?.Trim()};var n=0;
  foreach(var source in r.Lines){var line=order.Lines.SingleOrDefault(x=>x.Id==source.SalesOrderLineId);if(line is null||source.Quantity<=0||source.Quantity>line.ReservedQuantity-line.ShippedQuantity)return ApiResponse<object>.Error("Invalid or insufficiently reserved shipment quantity.",400);var tracking=await db.Products.AsNoTracking().Where(x=>x.Id==line.ProductId&&x.IsActive).Select(x=>x.TrackingType).FirstOrDefaultAsync(ct);if(tracking==InventoryTrackingType.Lot&&(p.RequireLotForLotTracked||trace.RequireLotForLotTrackedProducts)&&!line.InventoryLotId.HasValue)return ApiResponse<object>.Error("Lot is required for lot-tracked shipment products.",400);var serialIds=(source.InventorySerialIds??Array.Empty<long>()).Append(line.InventorySerialId??0).Where(x=>x>0).Distinct().ToArray();if(tracking==InventoryTrackingType.Serial&&((p.RequireSerialForSerialTracked||trace.RequireSerialForSerialTrackedProducts)&&serialIds.Length==0||source.Quantity!=serialIds.Length))return ApiResponse<object>.Error("Selected serial count must match shipment quantity.",400);if(tracking!=InventoryTrackingType.Serial&&serialIds.Length>0)return ApiResponse<object>.Error("Serials can only be selected for serial-tracked products.",400);if(serialIds.Length>0){var available=await db.InventoryBalances.AsNoTracking().CountAsync(x=>serialIds.Contains(x.InventorySerialId??0)&&x.ProductId==line.ProductId&&x.WarehouseId==order.WarehouseId&&x.StorageLocationId==line.StorageLocationId&&x.AvailableQuantity>0,ct);if(available!=serialIds.Length)return ApiResponse<object>.Error("One or more selected serials are not available at the shipment location.",400);}if(line.InventoryLotId.HasValue){var selected=await db.InventoryLots.AsNoTracking().Where(x=>x.Id==line.InventoryLotId).Select(x=>new{x.ExpiryDate,x.IsBlocked}).FirstOrDefaultAsync(ct);if(selected is null||selected.IsBlocked)return ApiResponse<object>.Error("Selected lot is missing or blocked.",400);if(trace.BlockExpiredShipments&&selected.ExpiryDate.HasValue&&selected.ExpiryDate.Value<r.ShipmentDate)return ApiResponse<object>.Error("Expired lots cannot be shipped.",400);if(trace.EnforceFefoOnShipments&&selected.ExpiryDate.HasValue){var earliest=await db.InventoryBalances.AsNoTracking().Where(x=>x.ProductId==line.ProductId&&x.WarehouseId==order.WarehouseId&&x.AvailableQuantity>0&&x.InventoryLotId.HasValue).Join(db.InventoryLots.AsNoTracking().Where(x=>x.IsActive&&!x.IsBlocked&&x.ExpiryDate.HasValue),b=>b.InventoryLotId,l=>(long?)l.Id,(b,l)=>l.ExpiryDate).MinAsync(ct);if(earliest.HasValue&&selected.ExpiryDate.Value>earliest.Value)return ApiResponse<object>.Error("FEFO is enabled; an earlier expiring lot must be shipped first.",400);}}if(serialIds.Length>0){foreach(var serialId in serialIds)e.Lines.Add(new ShipmentLine{LineNumber=++n,SalesOrderLineId=line.Id,ProductId=line.ProductId,UnitId=line.UnitId,StorageLocationId=line.StorageLocationId,InventoryStatusId=line.InventoryStatusId,InventoryLotId=line.InventoryLotId,InventorySerialId=serialId,Quantity=1});}else e.Lines.Add(new ShipmentLine{LineNumber=++n,SalesOrderLineId=line.Id,ProductId=line.ProductId,UnitId=line.UnitId,StorageLocationId=line.StorageLocationId,InventoryStatusId=line.InventoryStatusId,InventoryLotId=line.InventoryLotId,InventorySerialId=null,Quantity=source.Quantity});}
  if(!trace.AllowMixedLotsPerDocument&&e.Lines.Where(x=>x.InventoryLotId.HasValue).GroupBy(x=>x.ProductId).Any(g=>g.Select(x=>x.InventoryLotId).Distinct().Count()>1))return ApiResponse<object>.Error("Mixed lots for the same product are disabled by traceability parameters.",400);
  await u.Repository<Shipment>().AddAsync(e,ct);await u.SaveChangesAsync(ct);if(trade is not null){await u.Repository<TradeDocumentLink>().AddAsync(new(){TradeDossierId=trade.Id,LinkType=TradeLinkType.Shipment,SourceId=e.Id,ReferenceNumber=e.ShipmentNumber},ct);foreach(var line in e.Lines)await u.Repository<TradeDocumentLink>().AddAsync(new(){TradeDossierId=trade.Id,LinkType=TradeLinkType.Shipment,SourceId=e.Id,SourceLineId=line.Id,LinkedQuantity=line.Quantity,ReferenceNumber=e.ShipmentNumber},ct);await u.SaveChangesAsync(ct);}if(reserved is not null)await numberSeries.MarkUsedAsync(reserved.UsageId,e.Id,ct);return ApiResponse<object>.Ok(new{e.Id,e.ShipmentNumber,e.Status,e.TradeDossierId,NumberSeriesUsageId=reserved?.UsageId});
 }
 public async Task<ApiResponse<object>>ShipAsync(long id,CancellationToken ct)
 {
  var e=await u.Repository<Shipment>().Query(true).Include(x=>x.Lines).Include(x=>x.SalesOrder).ThenInclude(x=>x.Lines).FirstOrDefaultAsync(x=>x.Id==id,ct);if(e is null)return ApiResponse<object>.Error("Shipment not found.",404);if(e.TradeDossierId.HasValue){var trade=await db.TradeDossiers.AsNoTracking().FirstOrDefaultAsync(x=>x.Id==e.TradeDossierId,ct);if(trade is null||trade.Direction!=TradeDirection.Export||trade.Status<TradeDossierStatus.ExitAuthorized)return ApiResponse<object>.Error("Export shipment requires customs exit authorization.",409);}var settings=await parameters.ResolveSettingsAsync(e.SalesOrder.BranchId,e.WarehouseId,ct);if(settings.RequirePackedBeforeShipment&&e.Status!=ShipmentStatus.Packed)return ApiResponse<object>.Error("Shipment must be packed before posting.",409);if(!settings.RequirePackedBeforeShipment&&e.Status is not(ShipmentStatus.Draft or ShipmentStatus.Packed))return ApiResponse<object>.Error("Shipment is not postable.",409);
  ReservedNumber? noteReserved=null;if(settings.AutoCreateDeliveryNote)noteReserved=await numberSeries.ReserveAsync(new("Shipping","DeliveryNoteNumber",null,e.SalesOrder.BranchId,e.WarehouseId,null,e.SalesOrder.CustomerId,null,settings.DeliveryNoteScenario.ToString(),e.ShipmentDate,"DeliveryNote"),ct);DeliveryNote? note=null;await u.ExecuteInTransactionAsync(async t=>{var post=e.Lines.Select(x=>new PostInventoryLine(x.ProductId,x.UnitId,e.WarehouseId,x.StorageLocationId,x.InventoryStatusId,x.InventoryLotId,x.InventorySerialId,x.Quantity,null,x.Id,null)).ToList();var posting=await inventory.PostAsync(new($"SHIPMENT:{e.Id}","Shipment",e.Id,e.ShipmentNumber,e.ShipmentDate.ToDateTime(TimeOnly.MinValue),InventoryMovementType.SalesShipment,InventoryMovementDirection.Issue,settings.InventoryCurrencyCode,post),t);if(!posting.Success)throw new InvalidOperationException(posting.Message);foreach(var line in e.Lines){var so=e.SalesOrder.Lines.Single(x=>x.Id==line.SalesOrderLineId);so.ShippedQuantity+=line.Quantity;so.Status=so.ShippedQuantity>=so.OrderedQuantity?SalesLineStatus.Shipped:SalesLineStatus.PartiallyShipped;var reservation=await u.Repository<InventoryReservation>().FirstOrDefaultAsync(x=>x.SourceType=="SalesOrder"&&x.SourceLineId==so.Id&&x.Status==ReservationStatus.Active,true,t);if(reservation!=null){reservation.ConsumedQuantity+=line.Quantity;reservation.Status=reservation.ConsumedQuantity>=reservation.Quantity?ReservationStatus.Consumed:ReservationStatus.Active;}var balance=await u.Repository<InventoryBalance>().FirstOrDefaultAsync(x=>x.ProductId==line.ProductId&&x.WarehouseId==e.WarehouseId&&x.StorageLocationId==line.StorageLocationId&&x.InventoryStatusId==line.InventoryStatusId&&x.InventoryLotId==line.InventoryLotId&&x.InventorySerialId==line.InventorySerialId,true,t);if(balance!=null){balance.ReservedQuantity=Math.Max(0,balance.ReservedQuantity-line.Quantity);balance.AvailableQuantity=balance.PhysicalQuantity-balance.ReservedQuantity;}}e.InventoryPostingId=posting.Data!.PostingId;e.Status=ShipmentStatus.Shipped;e.ShippedAt=DateTime.UtcNow;e.SalesOrder.Status=e.SalesOrder.Lines.All(x=>x.Status==SalesLineStatus.Shipped)?SalesOrderStatus.Shipped:SalesOrderStatus.PartiallyShipped;if(settings.AutoCreateDeliveryNote){note=new DeliveryNote{DeliveryNoteNumber=noteReserved!.DocumentNumber,ShipmentId=e.Id,IssueDate=DateTime.UtcNow,Status=settings.DefaultDeliveryNoteStatus,Scenario=settings.DeliveryNoteScenario};await u.Repository<DeliveryNote>().AddAsync(note,t);}await u.SaveChangesAsync(t);},ct);if(noteReserved is not null&&note is not null)await numberSeries.MarkUsedAsync(noteReserved.UsageId,note.Id,ct);return ApiResponse<object>.Ok(new{e.Id,e.InventoryPostingId,DeliveryNoteId=note?.Id,DeliveryNoteNumber=note?.DeliveryNoteNumber,DeliveryNoteNumberSeriesUsageId=noteReserved?.UsageId});
 }
}


